CREATE TABLE IF NOT EXISTS collection_jobs (id BIGSERIAL PRIMARY KEY, tenant_id BIGINT NOT NULL REFERENCES tenants(id) ON DELETE CASCADE, target_type TEXT NOT NULL CHECK (target_type IN ('account','media','hashtag','ad_search','export')), target_ref TEXT NOT NULL, source_name TEXT NOT NULL, schedule_mode TEXT NOT NULL CHECK (schedule_mode IN ('manual','recurring','webhook','backfill')), status TEXT NOT NULL CHECK (status IN ('queued','running','succeeded','failed','deadletter')), created_at TIMESTAMPTZ NOT NULL DEFAULT now());
